@dataclass
class VMState:
    vm_pc: int = 0
    vm_mu: int = 0
    vm_err: bool = False
    vm_regs: List[int] = field(default_factory=lambda: [0] * REG_COUNT)
    vm_mem: List[int] = field(default_factory=lambda: [0] * MEM_SIZE)
    vm_csrs: CSRState = field(default_factory=CSRState)
    vm_graph: partitionGraph = field(default_factory=partitionGraph)
    vm_mu_tensor: List[int] = field(default_factory=lambda: [0] * TENSOR_SIZE)
    vm_logic_acc: int = 0
    vm_mstatus: int = 0
    vm_witness: List[int] = field(default_factory=lambda: [0] * 8)
    vm_certified: bool = False

    @classmethod
    def default(cls) -> "VMState":
        return cls(
            vm_pc=0,
            vm_mu=0,
            vm_err=False,
            vm_regs=[0] * REG_COUNT,
            vm_mem=[0] * MEM_SIZE,
            vm_csrs=CSRState(),
            vm_graph=partitionGraph(),
            vm_mu_tensor=[0] * TENSOR_SIZE,
            vm_logic_acc=0,
            vm_mstatus=0,
            vm_witness=[0] * 8,
            vm_certified=False,
        )

    def to_json_dict(self) -> dict:
        mods = []
        for mid, ms in self.vm_graph.pg_modules:
            mods.append({
                "id": mid,
                "region": ms.module_region,
                "axioms": len(ms.module_axioms),
                "axiom_strings": ms.module_axioms,
                "mu_tensor": list(ms.module_mu_tensor),
            })
        morphs = []
        for morph_id, ms in self.vm_graph.pg_morphisms:
            morphs.append({
                "id": morph_id,
                "source": ms.morph_source,
                "target": ms.morph_target,
                "is_identity": ms.morph_is_identity,
                "coupling": {
                    "label": ms.morph_coupling.coupling_label,
                    "pairs": [[a, b] for (a, b) in ms.morph_coupling.coupling_pairs],
                },
            })
        return {
            "pc": self.vm_pc,
            "mu": self.vm_mu,
            "err": self.vm_err,
            "csr_err_code": self.vm_csrs.csr_err,
            "regs": list(self.vm_regs),
            "mem": (lambda m: m[:next((len(m)-i for i,v in enumerate(reversed(m)) if v!=0), 0)])(list(self.vm_mem)),
            "mu_tensor": list(self.vm_mu_tensor),
            "logic_acc": self.vm_logic_acc,
            "mstatus": self.vm_mstatus,
            "certified": self.vm_certified,
            "witness": list(self.vm_witness),
            "csrs": {
                "cert_addr": self.vm_csrs.csr_cert_addr,
                "status": self.vm_csrs.csr_status,
                "err": self.vm_csrs.csr_err,
                "heap_base": self.vm_csrs.csr_heap_base,
            },
            "graph": {
                "next_id": self.vm_graph.pg_next_id,
                "modules": mods,
                "next_morph_id": self.vm_graph.pg_next_morph_id,
                "morphisms": morphs,
            },
        }

    def to_json(self) -> str:
        # Use compact JSON (no spaces) so OCaml parse_json_int_array finds "key":[ correctly
        body = json.dumps(self.to_json_dict(), separators=(',', ':'))
        mac = _compute_state_mac(body)
        return body[:-1] + ',"_mac":"' + mac + '"' + '}'

    @classmethod
    def from_json(cls, text: str) -> "VMState":
        d = json.loads(text)
        csrs = d.get("csrs", {})
        graph = d.get("graph", {})
        mods = []
        for m in graph.get("modules", []):
            ms = moduleState(
                module_region=list(m.get("region", [])),
                module_axioms=list(m.get("axiom_strings", [])),
                module_mu_tensor=list(m.get("mu_tensor", [0] * TENSOR_SIZE)),
            )
            mods.append((int(m["id"]), ms))
        morphs = []
        for m in graph.get("morphisms", []):
            coupling = m.get("coupling", {})
            pairs = []
            for p in coupling.get("pairs", []):
                if isinstance(p, (list, tuple)) and len(p) >= 2:
                    pairs.append((int(p[0]), int(p[1])))
            ms = MorphismState(
                morph_source=int(m.get("source", 0)),
                morph_target=int(m.get("target", 0)),
                morph_coupling=CouplingData(
                    coupling_pairs=pairs,
                    coupling_label=str(coupling.get("label", "")),
                ),
                morph_is_identity=bool(m.get("is_identity", False)),
            )
            morphs.append((int(m["id"]), ms))
        return cls(
            vm_pc=int(d.get("pc", 0)),
            vm_mu=int(d.get("mu", 0)),
            vm_err=bool(d.get("err", False)),
            vm_regs=list(d.get("regs", [0] * REG_COUNT)),
            vm_mem=(lambda m: (m + [0] * MEM_SIZE)[:MEM_SIZE])(list(d.get("mem", []))),
            vm_csrs=CSRState(
                csr_cert_addr=int(csrs.get("cert_addr", 0)),
                csr_status=int(csrs.get("status", 0)),
                csr_err=int(d.get("csr_err_code", csrs.get("err", 0))),
                csr_heap_base=int(csrs.get("heap_base", 0)),
            ),
            vm_graph=partitionGraph(
                pg_next_id=int(graph.get("next_id", 1)),
                pg_modules=mods,
                pg_next_morph_id=int(graph.get("next_morph_id", 1)),
                pg_morphisms=morphs,
            ),
            vm_mu_tensor=list(d.get("mu_tensor", [0] * TENSOR_SIZE)),
            vm_logic_acc=int(d.get("logic_acc", 0)),
            vm_mstatus=int(d.get("mstatus", 0)),
            vm_witness=list(d.get("witness", [0] * 8)),
            vm_certified=bool(d.get("certified", False)),
        )

    @property
    def pc(self) -> int: return self.vm_pc
    @property
    def mu(self) -> int: return self.vm_mu
    @property
    def err(self) -> bool: return self.vm_err
    @property
    def regs(self) -> List[int]: return self.vm_regs
    @property
    def mem(self) -> List[int]: return self.vm_mem
    @property
    def csrs(self) -> Dict[str, int]:
        return {"cert_addr": self.vm_csrs.csr_cert_addr, "status": self.vm_csrs.csr_status,
                "err": self.vm_csrs.csr_err, "heap_base": self.vm_csrs.csr_heap_base}
    @property
    def mu_tensor(self) -> List[int]: return self.vm_mu_tensor
    @property
    def logic_acc(self) -> int: return self.vm_logic_acc
    @property
    def mstatus(self) -> int: return self.vm_mstatus
    @property
    def witness(self) -> List[int]: return self.vm_witness
    @property
    def certified(self) -> bool: return self.vm_certified
    @property
    def supra_cert(self) -> bool: return self.vm_csrs.csr_cert_addr != 0
    @property
    def modules(self) -> list:
        from types import SimpleNamespace
        return [SimpleNamespace(id=mid, region=list(ms.module_region), axioms=len(ms.module_axioms))
                for mid, ms in self.vm_graph.pg_modules]
    @property
    def graph(self) -> "partitionGraph": return self.vm_graph

